import Vue from 'vue'
import Router from 'vue-router'
import Admin from '../components/Admin'
import About from '../components/About'
import Index from '../components/Index'
import AddUser from '../components/AddUser'
import Detail from '../components/Detail'
import UserEdit from '../components/UserEdit'
Vue.use(Router)

export default new Router({
  routes: [
    {
      path: '/',
      name: 'admin',
      component: Admin
    } ,{
      path: '/index',
      name: 'index',
      component: Index
    } ,{
      path: '/about',
      name: 'about',
      component:About
    },{
      path: '/addUser',
      name: 'addUser',
      component:AddUser
    },{
      path: '/detail/:id',
      name: 'detail',
      component:Detail
    }
    ,{
      path: '/edit/:id',
      name: 'edit',
      component:UserEdit
    },
  ],
  mode:"history"
})



