<template>
  <div class="detail" v-show="submit">
    <router-link to="/" class="btn btn-default">返回</router-link>
    <header>
      <h3>{{user.name}}</h3>
      <div class="container col-lg-offset-10">
        <a href="javascript:;" class="btn btn-danger " v-on:click.prevent ="del">删除</a>
        <router-link v-bind:to="'/edit/'+this.id" class="btn btn-primary ">编辑</router-link>
      </div>
    </header>
    <div class="panel panel-default panel-body"><span class="glyphicon glyphicon-phone"></span>{{user.phone}}</div>
      <div class="panel panel-default panel-body"><span class="glyphicon glyphicon-envelope"></span>{{user.email}}</div>
      <div class="panel panel-default panel-body"><span class="glyphicon glyphicon-asterisk"></span>{{user.school}}</div>
      <div class="panel panel-default panel-body"><span class="glyphicon glyphicon-education"></span>{{user.education}}</div>
      <div class="panel panel-default panel-body"><span class="glyphicon glyphicon-wrench"></span>{{user.profession}}</div>
      <div class="panel panel-default panel-body"><span class="glyphicon glyphicon-user"></span>{{user.introduce}}</div>
  </div>
</template>
<script>
  export default{
    data(){
      return{
        id: this.$route.params.id,
        user:{},
        submit:true
      }
    },
    created(){
     this.axios.get("http://localhost:3000/user/" + this.id).
       then((res) => {
         this.user = res.data
     })
    },
    updated(){
      this.axios.get("http://localhost:3000/user/" + this.id).
      then((res) => {
        this.user = res.data
      })
    },
    methods:{
      del(){
        this.axios.delete("http://localhost:3000/user/" + this.id);
        this.submit = false;
        this.$router.push({path:'/'});
       this.router.go(0);
      }
    }
  }
</script>
<style scoped>
    .detail{
      width:1000px;
      margin:0 auto;
    }
  .container{
    margin-bottom:20px
  }
  span{
   padding-right:10px;
  }
</style>



