<template>
  <div class="add container">
    <div v-bind:class="[flag ? hidden : show]"  role="alert">
      <button type="button" class="close" data-dismiss="alert" aria-label="Close"><span aria-hidden="true">&times;</span></button>
     用户添加成功！
    </div>
    <h3>添加用户</h3>
    <form class="form-horizontal" v-show="flag">
      <div class="form-group">
        <label for="name" class="control-label">姓名</label>
        <input type="text" class="form-control" id="name" placeholder="name" v-model="user.name">
      </div>
      <div class="form-group">
        <label for="phone" class="control-label">电话</label>
        <input type="text" class="form-control" id="phone" placeholder="phone" v-model="user.phone">
      </div>
      <div class="form-group">
        <label for="email" class="control-label">邮箱</label>
        <input type="email" class="form-control" id="email" placeholder="email" v-model="user.email">
      </div>
      <div class="form-group">
        <label for="education" class="control-label">学历</label>
        <input type="text" class="form-control" id="education" placeholder="education" v-model="user.education">
      </div>
      <div class="form-group">
        <label for="school" class="control-label">毕业学校</label>
        <input type="text" class="form-control" id="school" placeholder="school" v-model="user.school">
      </div>
      <div class="form-group">
        <label for="profession" class="control-label">职业</label>
        <input type="text" class="form-control" id="profession" placeholder="profession" v-model="user.profession">
      </div>
      <div class="form-group">
        <label for="introduce" class="control-label">个人简介</label>
        <textarea class="form-control" id="introduce" v-model="user.introduce"></textarea>
      </div>
      <div class="form-group">
          <button  class=" btn btn-primary" v-on:click.prevent="add">提交</button>
      </div>
    </form>
  </div>
</template>
<script>
  export default{
    data(){
      return{
          user:{
            name:"",
            phone:"",
            email:"",
            education:"",
            school:"",
            profession:"",
            introduce:"",

          }, show:"alert alert-warning alert-dismissible",
              hidden:"none",
        flag:true
      }
    },methods:{
      add(){
        var bool = this.user.name !== "" && this.user.phone !== ""  &&this.user.email !== "" && this.user.education !== "" && this.user.school !== "" && this.user.profession !=="" &&  this.user.introduce !== ""
        if(bool){
          console.log(111)
        this.axios.post("http://localhost:3000/user",this.user).then(() =>{
          console.log(222)
              this.flag = false;
          setTimeout(()=>{
            this.$router.push({path:'/'});
          },2000)
        })
        }else{
            alert("请将未填信息补全！")
        }
      }
    }
  }
</script>
<style>
    .add{
      width:1000px;
      margin:100px auto;
      background:#eee;
    }
    .alert{
      margin-top:-100px;
    }
    h3{
      text-align:center;
    }
    label{
      width:6%;
    }
  input{
    width:50%;
  }
  .none{
    display:none;
  }
</style>



