<template>
  <div class="admin">
    <h3>用户管理系统</h3>
    <input type="text" placeholder="搜索" v-model="value">
    <table class="table table-hover">
      <tr>
        <th>姓名</th>
        <th>电话</th>
        <th>邮箱</th>
      </tr>
      <tr v-for="user in filterUser">
        <td>{{user.name}}</td>
        <td>{{user.phone}}</td>
        <td>{{user.email}}</td>
        <td>
          <router-link :to="'/detail/' + user.id" class="btn btn-primary btn-sm">详情</router-link>
        </td>
      </tr>
    </table>
  </div>
</template>
<script>
  export default {
    name: 'Admin',
    data() {
      return {
        users: [],
        value: ""
      }
    }
    , created() {
      this.axios.get("http://localhost:3000/user")
        .then((res) => {
          this.users = res.data;
        })
    },
    computed: {
      filterUser() {
        return this.users.filter((user) => {
            return user.name.match(this.value)
          }
        )
      }
    }
  }
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>
  .admin {
    width: 1000px;
    height: 1000px;
    margin: 50px auto;
  }

  h3 {
    border-bottom: 2px solid #ddd;
    font-weight: 600;
    padding-bottom: 5px;
  }

  input {
    width: 100%;
    margin-top: 10px;
    border-radius: 5px;
    outline: none;
    padding: 5px;
  }

  tr {
    font-size: 12px;
    border-bottom: 1px solid #eee;
    margin: 10px;
  }

  tr:nth-child(2n) {
    background: #eee;
  }
</style>



